description:
Create the DialogStore behaviour that defines the interface for dialog state persistence.

## Behaviour Definition

```elixir
defmodule ParrotSip.DialogStore do
  @moduledoc """
  Behaviour for dialog state persistence and replication.

  Implementations can choose different strategies:
  - ETS: Local only, fastest, single node
  - Replicated: PubSub broadcast, multi-node cluster
  - Mnesia: Durable, survives cluster restart
  """

  @type dialog_id :: String.t()
  @type dialog_state :: %{
    id: dialog_id(),
    state: :early | :confirmed | :terminated,
    call_id: String.t(),
    local_tag: String.t(),
    remote_tag: String.t(),
    local_uri: String.t(),
    remote_uri: String.t(),
    remote_target: String.t(),
    local_seq: non_neg_integer(),
    remote_seq: non_neg_integer(),
    route_set: [String.t()],
    owning_node: node(),
    created_at: DateTime.t(),
    updated_at: DateTime.t()
  }

  @doc "Store or update dialog state"
  @callback store(dialog_id, dialog_state) :: :ok | {:error, term()}

  @doc "Store dialog state asynchronously (fire and forget)"
  @callback store_async(dialog_id, dialog_state) :: :ok

  @doc "Fetch dialog state by ID"
  @callback fetch(dialog_id) :: {:ok, dialog_state} | {:error, :not_found}

  @doc "Delete dialog state"
  @callback delete(dialog_id) :: :ok

  @doc "List all dialogs owned by a specific node (for recovery)"
  @callback list_by_node(node()) :: [dialog_state]

  @doc "List all dialogs (for debugging/admin)"
  @callback list_all() :: [dialog_state]

  @doc "Transfer ownership of a dialog to a new node"
  @callback transfer_ownership(dialog_id, new_node :: node()) :: :ok | {:error, term()}
end
```

## Helper Functions

```elixir
defmodule ParrotSip.DialogStore do
  # ... callbacks above ...

  @doc "Get configured implementation module"
  def impl do
    Application.get_env(:parrot_sip, :dialog_store, ParrotSip.DialogStore.Replicated)
  end

  # Delegate to configured implementation
  defdelegate store(id, state), to: impl()
  defdelegate store_async(id, state), to: impl()
  defdelegate fetch(id), to: impl()
  defdelegate delete(id), to: impl()
  defdelegate list_by_node(node), to: impl()
  defdelegate list_all(), to: impl()
  defdelegate transfer_ownership(id, node), to: impl()
end
```

